            let sealed = try AES.GCM.seal(plaintext, using: key)
            guard let combined = sealed.combined else { throw BankingError.cryptoFailure }
            return EncryptedBlob(combined: combined)
        } catch {
            throw BankingError.cryptoFailure
        }
    }

    public func decrypt(_ blob: EncryptedBlob) throws -> Data {
