public protocol LedgerPersistence {
    func load() throws -> LedgerSnapshot
    func save(_ snapshot: LedgerSnapshot) throws
    func wipe() throws
}

public final class EncryptedFileLedgerPersistence: LedgerPersistence {
    private let crypto: CryptoService
    private let url: URL
    private let encoder: JSONEncoder
    private let decoder: JSONDecoder

    public init(
        crypto: CryptoService = CryptoService(),
        fileName: String = "ledger.dat",
        directory: FileManager.SearchPathDirectory = .applicationSupportDirectory
    ) throws {
        self.crypto = crypto
        let fm = FileManager.default
        let base = try fm.url(for: directory, in: .userDomainMask, appropriateFor: nil, create: true)
        let dir = base.appendingPathComponent("BankingModule", isDirectory: true)
        if !fm.fileExists(atPath: dir.path) {
            try fm.createDirectory(at: dir, withIntermediateDirectories: true)
        }
        self.url = dir.appendingPathComponent(fileName, isDirectory: false)

        let enc = JSONEncoder()
        enc.dateEncodingStrategy = .iso8601
        self.encoder = enc

        let dec = JSONDecoder()
        dec.dateDecodingStrategy = .iso8601
        self.decoder = dec
    }

    public func load() throws -> LedgerSnapshot {
        let fm = FileManager.default
        guard fm.fileExists(atPath: url.path) else { return LedgerSnapshot() }
        do {
            let data = try Data(contentsOf: url, options: [.mappedIfSafe])
            let blob = try decoder.decode(EncryptedBlob.self, from: data)
            let plaintext = try crypto.decrypt(blob)
            return try decoder.decode(LedgerSnapshot.self, from: plaintext)
        } catch is BankingError {
            throw error
        } catch {
            throw BankingError.dataCorrupted
        }
    }

    public func save(_ snapshot: LedgerSnapshot) throws {
        do {
            let plaintext = try encoder.encode(snapshot)
            let blob = try crypto.encrypt(plaintext)
            let data = try encoder.encode(blob)
            try data.write(to: url, options: [.atomic, .completeFileProtection])
        } catch is BankingError {
            throw error
        } catch {
            throw BankingError.persistenceFailure
        }
    }

    public func wipe() throws {
        let fm = FileManager.default
        if fm.fileExists(atPath: url.path) {
            try fm.removeItem(at: url)
        }
    }
}

