public final class BankingLedger {
    private let persistence: LedgerPersistence
    private let queue = DispatchQueue(label: "com.example.banking.ledger.queue", qos: .userInitiated)
    private var snapshot: LedgerSnapshot

    public init(persistence: LedgerPersistence) throws {
        self.persistence = persistence
        self.snapshot = try persistence.load()
    }

    public func getAccounts() -> [Account] {
        queue.sync { snapshot.accounts.sorted { $0.displayName.localizedCaseInsensitiveCompare($1.displayName) == .orderedAscending } }
    }

    public func getTransactions(for accountId: UUID) -> [Transaction] {
        queue.sync {
            snapshot.transactions
                .filter { $0.accountId == accountId }
                .sorted { $0.createdAt > $1.createdAt }
        }
    }

    public func getBalance(for accountId: UUID) throws -> Money {
        try queue.sync {
            guard let acct = snapshot.accounts.first(where: { $0.id == accountId }) else { throw BankingError.accountNotFound }
            return Money(cents: acct.balanceCents, currencyCode: acct.currencyCode)
        }
    }

    @discardableResult
    public func createAccount(displayName: String, currencyCode: String, openingBalanceCents: Int64 = 0) throws -> Account {
        try queue.sync {
            var acct = Account(displayName: displayName, currencyCode: currencyCode, balanceCents: openingBalanceCents, updatedAt: Date())
            snapshot.accounts.append(acct)
            snapshot.lastUpdatedAt = Date()
            try persistence.save(snapshot)
            return acct
        }
    }

    public func deleteAccount(accountId: UUID) throws {
        try queue.sync {
            snapshot.accounts.removeAll { $0.id == accountId }
            snapshot.transactions.removeAll { $0.accountId == accountId }
            snapshot.lastUpdatedAt = Date()
            try persistence.save(snapshot)
        }
    }

    @discardableResult
    public func postTransaction(
        accountId: UUID,
        type: TransactionType,
        amountCents: Int64,
        currencyCode: String,
        memo: String? = nil,
        idempotencyKey: UUID = UUID()
    ) throws -> Transaction {
        try queue.sync {
            guard amountCents > 0 else { throw BankingError.invalidAmount }
            guard let idx = snapshot.accounts.firstIndex(where: { $0.id == accountId }) else { throw BankingError.accountNotFound }
            guard snapshot.accounts[idx].currencyCode.uppercased() == currencyCode.uppercased() else { throw BankingError.currencyMismatch }

            if snapshot.transactions.contains(where: { $0.id == idempotencyKey }) {
                throw BankingError.duplicateTransaction
            }

            var acct = snapshot.accounts[idx]
            let delta: Int64 = (type == .credit) ? amountCents : -amountCents

            if delta < 0 && acct.balanceCents + delta < 0 {
                throw BankingError.insufficientFunds
            }

            acct.balanceCents += delta
            acct.updatedAt = Date()
            snapshot.accounts[idx] = acct

            let tx = Transaction(
                id: idempotencyKey,
                accountId: accountId,
                type: type,
                amountCents: amountCents,
                currencyCode: currencyCode.uppercased(),
                createdAt: Date(),
                memo: memo
            )
            snapshot.transactions.append(tx)
            snapshot.lastUpdatedAt = Date()
            try persistence.save(snapshot)
            return tx
        }
    }

    public func refreshFromDisk() throws {
        try queue.sync {
            snapshot = try persistence.load()
        }
    }

    public func wipeAllData() throws {
        try queue.sync {
            snapshot = LedgerSnapshot()
            try persistence.wipe()
        }
    }
}

// MARK: - Formatting

public struct CurrencyFormatter {
    private let formatter: NumberFormatter

    public init(locale: Locale = .current, currencyCode: String) {
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.locale = locale
        f.currencyCode = currencyCode
        f.maximumFractionDigits = 2
        f.minimumFractionDigits = 2
        self.formatter = f
    }

    public func string(fromCents cents: Int64) -> String {
        let value = Decimal(cents) / 100
        return formatter.string(from: value as NSDecimalNumber) ?? "\(value)"
    }
}

// MARK: - View Model (UIKit/SwiftUI friendly)

#if canImport(Combine)
import Combine

@MainActor
public final class BankingViewModel: ObservableObject {
    @Published public private(set) var accounts: [Account] = []
    @Published public private(set) var selectedAccount: Account?
    @Published public private(set) var transactions: [Transaction] = []
    @Published public private(set) var balanceText: String = ""

    private let ledger: BankingLedger
    private var currencyFormatter: CurrencyFormatter?

    public init(ledger: BankingLedger) {
        self.ledger = ledger
        reloadAccounts()
    }

    public func reloadAccounts() {
        let accts = ledger.getAccounts()
        accounts = accts
        if selectedAccount == nil, let first = accts.first {
            selectAccount(first.id)
        } else if let sel = selectedAccount {
            selectAccount(sel.id)
        }
    }

    public func selectAccount(_ accountId: UUID) {
        guard let acct = ledger.getAccounts().first(where: { $0.id == accountId }) else {
            selectedAccount = nil
            transactions = []
            balanceText = ""
            return
        }
        selectedAccount = acct
        currencyFormatter = CurrencyFormatter(currencyCode: acct.currencyCode)
        transactions = ledger.getTransactions(for: acct.id)
        if let money = try? ledger.getBalance(for: acct.id) {
            balanceText = currencyFormatter?.string(fromCents: money.cents) ?? ""
        } else {
            balanceText = ""
        }
    }

    public func createAccount(displayName: String, currencyCode: String, openingBalanceCents: Int64 = 0) async throws {
        _ = try ledger.createAccount(displayName: displayName, currencyCode: currencyCode, openingBalanceCents: openingBalanceCents)
        reloadAccounts()
    }

    public func postCredit(amountCents: Int64, memo: String? = nil) async throws {
        guard let acct = selectedAccount else { throw BankingError.accountNotFound }
        _ = try ledger.postTransaction(accountId: acct.id, type: .credit, amountCents: amountCents, currencyCode: acct.currencyCode, memo: memo)
        selectAccount(acct.id)
        reloadAccounts()
    }

    public func postDebit(amountCents: Int64, memo: String? = nil) async throws {
        guard let acct = selectedAccount else { throw BankingError.accountNotFound }
        _ = try ledger.postTransaction(accountId: acct.id, type: .debit, amountCents: amountCents, currencyCode: acct.currencyCode, memo: memo)
        selectAccount(acct.id)
        reloadAccounts()
    }

    public func wipeAll() async throws {
        try ledger.wipeAllData()
        reloadAccounts()
    }
}
#endif

